                            { icon: 'landscape', color: 'from-emerald-500 to-teal-500', title: 'nature' },
                            { icon: 'ramen_dining', color: 'from-orange-500 to-red-500', title: 'culture' },
                            { icon: 'train', color: 'from-blue-500 to-indigo-500', title: 'transportation' },
