                                </div>
                                <h3 className="text-2xl font-bold text-gray-900 mb-4">
                                    {t(`newsPage.niigataLife.${item.title}.title`)}
                                </h3>
                                <p className="text-gray-600 leading-relaxed">
                                    {t(`newsPage.niigataLife.${item.title}.description`)}
                                </p>
                            </div>
