                                {t('newsPage.niigataLife.gallery.title')}
                            </h3>
                        </div>
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                            {[
                                { video: data4Video, label: 'cityView' },
                                { video: data5Video, label: 'festivals' },
                                { video: data6Video, label: 'winterScenes' }
                            ].map((item, index) => (
                                <div key={index} className="group relative overflow-hidden rounded-2xl shadow-xl hover:shadow-2xl transition-all duration-500">
                                    <video autoPlay muted loop className="w-full h-64 object-cover group-hover:scale-110 transition-transform duration-700">
                                        <source src={item.video} type="video/mp4" />
                                        {t('newsPage.videoNotSupported')}
                                    </video>
                                    <div className="absolute inset-0 bg-gradient-to-t from-black/70 via-transparent to-transparent group-hover:from-black/50 transition-all duration-500"></div>
                                    <div className="absolute bottom-6 left-6 right-6">
                                        <div className="bg-white/20 backdrop-blur-md rounded-xl px-4 py-3 border border-white/30">
                                            <span className="text-white font-semibold text-lg">{t(`newsPage.niigataLife.gallery.${item.label}`)}</span>
                                        </div>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                </div>
            </section>
        </div>
    );
};

export default NewsPage;
